"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   curriculum: () => (/* binding */ curriculum),\n/* harmony export */   \"default\": () => (__WEBPACK_DEFAULT_EXPORT__)\n/* harmony export */ });\nconst curriculum = [\n    {\n        id: \"U1\",\n        number: 1,\n        name: \"走进物联网\",\n        description: \"了解物联网的基本概念、发展历程、体系架构和应用场景\",\n        lessons: [\n            {\n                id: \"L01\",\n                unitId: \"U1\",\n                number: 1,\n                name: \"认识物联网\",\n                duration: 45,\n                objectives: [\n                    \"了解物联网的基本概念和定义\",\n                    \"理解物联网与互联网的关系\",\n                    \"认识物联网在日常生活中的应用\"\n                ],\n                keyPoints: [\n                    \"物联网定义\",\n                    \"物联网特征\",\n                    \"物联网与互联网的区别\"\n                ],\n                difficulties: [\n                    \"理解物联网的全面感知、可靠传输、智能处理三大特征\"\n                ],\n                content: `\n# 第1课 认识物联网\n\n## 一、什么是物联网\n\n物联网（Internet of Things，简称IoT）是指通过**传感器、通信网络、软件系统**，把物品连接起来，实现物品的**识别、监控、管理**的网络。\n\n简单来说：**物联网 = 物品 + 互联网 + 智能**\n\n### 物联网的三大特征\n\n1. **全面感知**：利用各种传感器实时采集物品信息\n2. **可靠传输**：通过网络将信息传递到处理中心\n3. **智能处理**：对海量数据进行分析处理，实现智能控制\n\n## 二、物联网与互联网的关系\n\n| 对比项 | 互联网 | 物联网 |\n|--------|--------|--------|\n| 连接对象 | 人与人 | 物与物、人与物 |\n| 信息来源 | 人为输入 | 传感器自动采集 |\n| 应用目标 | 信息共享 | 智能控制 |\n\n## 三、生活中的物联网\n\n### 1. 智能家居\n- 智能音箱（小爱同学、天猫精灵）\n- 智能灯泡、智能插座\n- 智能门锁、智能摄像头\n\n### 2. 智慧交通\n- 共享单车（扫码开锁）\n- ETC不停车收费\n- 智能停车系统\n\n### 3. 智能穿戴\n- 智能手表（计步、心率监测）\n- 智能手环\n        `,\n                quizIds: [\n                    \"Q0101\",\n                    \"Q0102\",\n                    \"Q0103\"\n                ],\n                simulatorId: \"sim-home\"\n            },\n            {\n                id: \"L02\",\n                unitId: \"U1\",\n                number: 2,\n                name: \"物联网的发展历程\",\n                duration: 45,\n                objectives: [\n                    \"了解物联网的起源和发展阶段\",\n                    \"认识物联网发展的关键技术和里程碑\",\n                    \"理解物联网发展的必然趋势\"\n                ],\n                keyPoints: [\n                    \"物联网起源\",\n                    \"发展阶段\",\n                    \"关键技术\"\n                ],\n                difficulties: [\n                    \"理解推动物联网发展的技术因素\"\n                ],\n                content: `\n# 第2课 物联网的发展历程\n\n## 一、物联网的起源\n\n1999年，Kevin Ashton首次提出\"物联网\"概念，认为物品也应该能够\"说话\"。\n\n## 二、发展阶段\n\n### 第一阶段：概念提出期（1999-2005）\n- 概念诞生，RFID技术初步应用\n- 主要在物流、零售领域试点\n\n### 第二阶段：技术发展期（2005-2010）\n- 传感器技术进步\n- 无线通信网络建设\n- 应用场景扩展\n\n### 第三阶段：应用推广期（2010-2015）\n- 智能家居兴起\n- 智慧城市建设\n- 工业物联网发展\n\n### 第四阶段：快速发展期（2015至今）\n- 5G通信技术商用\n- AI与物联网融合\n- 万物互联时代到来\n\n## 三、推动发展的关键技术\n\n1. **传感器技术**：体积更小、功耗更低、精度更高\n2. **通信技术**：5G、NB-IoT、LoRa等\n3. **云计算**：海量数据存储和处理能力\n4. **人工智能**：智能分析和决策能力\n        `,\n                quizIds: [\n                    \"Q0201\",\n                    \"Q0202\"\n                ]\n            },\n            {\n                id: \"L03\",\n                unitId: \"U1\",\n                number: 3,\n                name: \"物联网的体系架构\",\n                duration: 45,\n                objectives: [\n                    \"理解物联网的三层体系架构\",\n                    \"了解每层的功能和技术\",\n                    \"认识架构中各层的协作关系\"\n                ],\n                keyPoints: [\n                    \"感知层\",\n                    \"网络层\",\n                    \"应用层\"\n                ],\n                difficulties: [\n                    \"理解三层架构的逻辑关系\"\n                ],\n                content: `\n# 第3课 物联网的体系架构\n\n## 物联网三层架构\n\n\\`\\`\\`\n┌─────────────────────────┐\n│      应用层              │  智能应用、数据处理\n├─────────────────────────┤\n│      网络层              │  信息传输、网络接入\n├─────────────────────────┤\n│      感知层              │  数据采集、设备控制\n└─────────────────────────┘\n\\`\\`\\`\n\n## 一、感知层\n\n**功能**：采集数据、识别物体\n\n**组成**：\n- 传感器：温度、湿度、光照、运动等\n- RFID读写器\n- 摄像头、GPS等\n\n## 二、网络层\n\n**功能**：传输数据、互联互通\n\n**组成**：\n- 有线网络：以太网\n- 无线网络：Wi-Fi、蓝牙、ZigBee\n- 移动通信：4G、5G、NB-IoT\n\n## 三、应用层\n\n**功能**：数据处理、智能应用\n\n**组成**：\n- 云计算平台\n- 数据分析系统\n- 应用程序\n        `,\n                quizIds: [\n                    \"Q0301\",\n                    \"Q0302\"\n                ]\n            },\n            {\n                id: \"L04\",\n                unitId: \"U1\",\n                number: 4,\n                name: \"物联网的应用场景\",\n                duration: 45,\n                objectives: [\n                    \"了解物联网的主要应用领域\",\n                    \"认识典型应用案例\",\n                    \"思考物联网应用的价值\"\n                ],\n                keyPoints: [\n                    \"智能家居\",\n                    \"智慧城市\",\n                    \"智慧农业\"\n                ],\n                difficulties: [\n                    \"理解物联网应用的技术实现\"\n                ],\n                content: `\n# 第4课 物联网的应用场景\n\n## 一、智能家居\n\n让家庭设备互联互通，实现智能化控制。\n\n### 应用举例\n- 语音控制家电\n- 手机远程控制\n- 自动化场景联动\n\n## 二、智慧城市\n\n利用物联网技术提升城市管理效率。\n\n### 应用举例\n- 智慧交通：信号灯优化、拥堵检测\n- 智慧环保：空气质量监测\n- 智慧安防：视频监控、应急响应\n\n## 三、智慧农业\n\n实现农业生产智能化、精准化。\n\n### 应用举例\n- 土壤监测：温湿度、酸碱度\n- 智能灌溉：自动浇水\n- 病虫害预警\n\n## 四、智慧医疗\n\n### 应用举例\n- 远程监护\n- 智能穿戴健康监测\n- 医疗设备管理\n        `,\n                quizIds: [\n                    \"Q0401\",\n                    \"Q0402\"\n                ],\n                simulatorId: \"sim-home\"\n            },\n            {\n                id: \"L05\",\n                unitId: \"U1\",\n                number: 5,\n                name: \"物联网的发展趋势\",\n                duration: 45,\n                objectives: [\n                    \"了解物联网的未来发展方向\",\n                    \"认识物联网与其他技术的融合\",\n                    \"培养对新兴技术的兴趣\"\n                ],\n                keyPoints: [\n                    \"AI+IoT\",\n                    \"边缘计算\",\n                    \"万物互联\"\n                ],\n                difficulties: [\n                    \"理解技术融合的意义\"\n                ],\n                content: `\n# 第5课 物联网的发展趋势\n\n## 一、人工智能与物联网融合\n\n**AIoT = AI + IoT**\n\n物联网提供数据，人工智能提供智能。\n\n应用场景：\n- 智能音箱的语音交互\n- 智能摄像头的物体识别\n- 自动驾驶汽车\n\n## 二、边缘计算\n\n将计算能力下放到网络边缘，减少延迟。\n\n优势：\n- 响应速度快\n- 降低云端压力\n- 保护数据隐私\n\n## 三、万物互联\n\n从\"人联网\"到\"物联网\"再到\"万物互联\"\n\n- 万物皆可连接\n- 万物皆可交互\n- 万物皆可智能\n\n## 四、安全与隐私\n\n物联网发展面临的安全挑战：\n- 设备安全\n- 数据隐私\n- 身份认证\n        `,\n                quizIds: [\n                    \"Q0501\"\n                ]\n            }\n        ]\n    },\n    {\n        id: \"U2\",\n        number: 2,\n        name: \"感知与识别\",\n        description: \"学习传感器、RFID、条码、图像识别、语音识别等感知识别技术\",\n        lessons: [\n            {\n                id: \"L06\",\n                unitId: \"U2\",\n                number: 6,\n                name: \"传感器基础知识\",\n                duration: 45,\n                objectives: [\n                    \"理解传感器的基本概念\",\n                    \"了解传感器的工作原理\",\n                    \"认识传感器的分类\"\n                ],\n                keyPoints: [\n                    \"传感器定义\",\n                    \"传感器组成\",\n                    \"传感器分类\"\n                ],\n                difficulties: [\n                    \"理解传感器的工作原理\"\n                ],\n                content: `\n# 第6课 传感器基础知识\n\n## 一、什么是传感器\n\n传感器是一种**检测装置**，能感受到被测量的信息，并将检测到的信息**转换成电信号**或其他形式输出，以满足信息的传输、处理、存储、显示、记录和控制等要求。\n\n## 二、传感器的组成\n\n\\`\\`\\`\n┌─────────┐      ┌─────────┐      ┌─────────┐\n│ 敏感元件 │ ──→ │ 转换元件 │ ──→ │ 信号调理 │\n└─────────┘      └─────────┘      └─────────┘\n    ↓                                    ↓\n  感知物理量                          输出电信号\n\\`\\`\\`\n\n## 三、传感器分类\n\n### 按工作原理分\n- 电阻式传感器\n- 电容式传感器\n- 电感式传感器\n- 光电式传感器\n\n### 按被测物理量分\n- 温度传感器\n- 湿度传感器\n- 光照传感器\n- 压力传感器\n- 速度传感器\n        `,\n                quizIds: [\n                    \"Q0601\",\n                    \"Q0602\"\n                ],\n                simulatorId: \"sim-sensor\"\n            },\n            {\n                id: \"L07\",\n                unitId: \"U2\",\n                number: 7,\n                name: \"常见的传感器\",\n                duration: 45,\n                objectives: [\n                    \"认识常见传感器的类型\",\n                    \"了解各种传感器的应用\",\n                    \"理解传感器选型原则\"\n                ],\n                keyPoints: [\n                    \"温度传感器\",\n                    \"湿度传感器\",\n                    \"光敏传感器\"\n                ],\n                difficulties: [\n                    \"区分不同传感器的应用场景\"\n                ],\n                content: `\n# 第7课 常见的传感器\n\n## 一、温度传感器\n\n**应用**：\n- 空调温控\n- 冰箱温度检测\n- 体温计\n\n## 二、湿度传感器\n\n**应用**：\n- 智能家居环境监测\n- 温室大棚湿度控制\n- 气象站\n\n## 三、光敏传感器\n\n**应用**：\n- 手机自动亮度调节\n- 楼道自动灯\n- 照相机曝光控制\n\n## 四、运动传感器（加速度传感器）\n\n**应用**：\n- 手机横竖屏切换\n- 计步器\n- 游戏体感控制\n\n## 五、声音传感器\n\n**应用**：\n- 语音控制\n- 声控灯\n- 噪音监测\n        `,\n                quizIds: [\n                    \"Q0701\",\n                    \"Q0702\"\n                ],\n                simulatorId: \"sim-sensor\"\n            },\n            {\n                id: \"L08\",\n                unitId: \"U2\",\n                number: 8,\n                name: \"认识RFID\",\n                duration: 45,\n                objectives: [\n                    \"理解RFID技术原理\",\n                    \"了解RFID的组成\",\n                    \"认识RFID的应用\"\n                ],\n                keyPoints: [\n                    \"RFID原理\",\n                    \"RFID组成\",\n                    \"RFID应用\"\n                ],\n                difficulties: [\n                    \"理解RFID的无线通信原理\"\n                ],\n                content: `\n# 第8课 认识RFID\n\n## 一、什么是RFID\n\nRFID（Radio Frequency Identification）即**射频识别**，是一种无线通信技术，可以通过无线电信号识别特定目标并读写相关数据。\n\n## 二、RFID系统组成\n\n\\`\\`\\`\n┌──────────┐    无线信号    ┌──────────┐\n│ RFID标签  │ ←─────────→ │ RFID读写器 │\n└──────────┘              └──────────┘\n                               ↓\n                          ┌──────────┐\n                          │ 数据库    │\n                          └──────────┘\n\\`\\`\\`\n\n### 1. RFID标签\n- 存储物品信息\n- 分为有源和无源两种\n\n### 2. RFID读写器\n- 发射射频信号\n- 读取/写入标签数据\n\n## 三、RFID应用\n\n- 门禁系统\n- 图书馆管理\n- 物流追踪\n- ETC收费\n        `,\n                quizIds: [\n                    \"Q0801\",\n                    \"Q0802\"\n                ],\n                simulatorId: \"sim-rfid\"\n            },\n            {\n                id: \"L09\",\n                unitId: \"U2\",\n                number: 9,\n                name: \"条码识别技术\",\n                duration: 45,\n                objectives: [\n                    \"了解条形码的原理\",\n                    \"认识二维码的特点\",\n                    \"理解条码识别的应用\"\n                ],\n                keyPoints: [\n                    \"条形码\",\n                    \"二维码\",\n                    \"扫码应用\"\n                ],\n                difficulties: [\n                    \"区分一维码和二维码的特点\"\n                ],\n                content: `\n# 第9课 条码识别技术\n\n## 一、一维条形码\n\n通过黑白相间的条纹表示信息。\n\n**特点**：\n- 信息容量小\n- 只能存储数字和字母\n- 一维方向编码\n\n## 二、二维码\n\n在水平和垂直方向都能存储信息。\n\n**特点**：\n- 信息容量大\n- 可存储汉字、图片\n- 容错能力强\n- 支持加密\n\n## 三、扫码应用\n\n- 商品识别\n- 移动支付\n- 添加好友\n- 网页跳转\n- 共享单车开锁\n        `,\n                quizIds: [\n                    \"Q0901\",\n                    \"Q0902\"\n                ]\n            },\n            {\n                id: \"L10\",\n                unitId: \"U2\",\n                number: 10,\n                name: \"图像识别初步\",\n                duration: 45,\n                objectives: [\n                    \"了解图像识别的概念\",\n                    \"认识图像识别的应用\",\n                    \"理解图像识别的基本流程\"\n                ],\n                keyPoints: [\n                    \"图像识别定义\",\n                    \"识别流程\",\n                    \"应用场景\"\n                ],\n                difficulties: [\n                    \"理解图像识别的技术原理\"\n                ],\n                content: `\n# 第10课 图像识别初步\n\n## 一、什么是图像识别\n\n利用计算机对图像进行处理、分析和理解，识别出图像中的目标对象。\n\n## 二、图像识别流程\n\n\\`\\`\\`\n图像输入 → 预处理 → 特征提取 → 分类识别 → 结果输出\n\\`\\`\\`\n\n## 三、应用场景\n\n- 人脸识别：门禁、支付、手机解锁\n- 车牌识别：停车场、交通违章\n- 文字识别：OCR、身份证识别\n- 物体识别：垃圾分类、商品识别\n        `,\n                quizIds: [\n                    \"Q1001\"\n                ]\n            },\n            {\n                id: \"L11\",\n                unitId: \"U2\",\n                number: 11,\n                name: \"语音识别入门\",\n                duration: 45,\n                objectives: [\n                    \"了解语音识别的概念\",\n                    \"理解语音识别的过程\",\n                    \"认识语音识别的应用\"\n                ],\n                keyPoints: [\n                    \"语音识别定义\",\n                    \"识别过程\",\n                    \"应用场景\"\n                ],\n                difficulties: [\n                    \"理解语音到文字的转换过程\"\n                ],\n                content: `\n# 第11课 语音识别入门\n\n## 一、什么是语音识别\n\n将人类的语音信号转换成文字或命令的技术。\n\n## 二、语音识别过程\n\n\\`\\`\\`\n语音输入 → 预处理 → 特征提取 → 模式匹配 → 结果输出\n\\`\\`\\`\n\n## 三、应用场景\n\n- 智能音箱（小爱同学、天猫精灵）\n- 语音输入法\n- 语音助手（Siri、小艺）\n- 智能客服\n- 车载语音控制\n        `,\n                quizIds: [\n                    \"Q1101\"\n                ],\n                simulatorId: \"sim-visualization\"\n            }\n        ]\n    },\n    {\n        id: \"U3\",\n        number: 3,\n        name: \"传感器与数据采集\",\n        description: \"深入学习各类传感器的使用和数据采集处理方法\",\n        lessons: [\n            {\n                id: \"L12\",\n                unitId: \"U3\",\n                number: 12,\n                name: \"温湿度传感器\",\n                duration: 45,\n                objectives: [\n                    \"掌握温湿度传感器的原理\",\n                    \"学会读取传感器数据\",\n                    \"理解数据的应用\"\n                ],\n                keyPoints: [\n                    \"DHT11/DHT22\",\n                    \"数据读取\",\n                    \"温度单位换算\"\n                ],\n                difficulties: [\n                    \"理解数字信号的读取过程\"\n                ],\n                content: `\n# 第12课 温湿度传感器\n\n## 一、常用温湿度传感器\n\n### DHT11\n- 温度范围：0-50°C\n- 湿度范围：20-90%RH\n- 精度：±2°C, ±5%RH\n\n### DHT22\n- 温度范围：-40-80°C\n- 湿度范围：0-100%RH\n- 精度：±0.5°C, ±2%RH\n\n## 二、数据读取\n\n传感器通过单总线数字信号输出数据。\n\n数据格式：湿度整数 + 湿度小数 + 温度整数 + 温度小数 + 校验和\n\n## 三、应用场景\n\n- 智能家居环境监测\n- 温室大棚监控\n- 仓储环境监测\n        `,\n                quizIds: [\n                    \"Q1201\",\n                    \"Q1202\"\n                ],\n                simulatorId: \"sim-sensor\"\n            },\n            {\n                id: \"L13\",\n                unitId: \"U3\",\n                number: 13,\n                name: \"光敏传感器\",\n                duration: 45,\n                objectives: [\n                    \"理解光敏电阻的工作原理\",\n                    \"学会使用光敏传感器\",\n                    \"了解光照强度测量\"\n                ],\n                keyPoints: [\n                    \"光敏电阻\",\n                    \"模拟信号\",\n                    \"AD转换\"\n                ],\n                difficulties: [\n                    \"理解光敏电阻的阻值变化\"\n                ],\n                content: `\n# 第13课 光敏传感器\n\n## 一、光敏电阻原理\n\n光敏电阻的阻值随光照强度变化：\n- 光照强 → 阻值小\n- 光照弱 → 阻值大\n\n## 二、电路连接\n\n光敏电阻与固定电阻组成分压电路，测量中间电压可计算光照强度。\n\n\\`\\`\\`\nVCC ──[光敏电阻]──┬──[固定电阻]── GND\n                  │\n               模拟输入\n\\`\\`\\`\n\n## 三、应用场景\n\n- 路灯自动控制\n- 手机屏幕亮度调节\n- 植物生长灯控制\n        `,\n                quizIds: [\n                    \"Q1301\"\n                ],\n                simulatorId: \"sim-sensor\"\n            },\n            {\n                id: \"L14\",\n                unitId: \"U3\",\n                number: 14,\n                name: \"运动传感器\",\n                duration: 45,\n                objectives: [\n                    \"了解加速度传感器原理\",\n                    \"理解运动检测方法\",\n                    \"学会应用运动数据\"\n                ],\n                keyPoints: [\n                    \"加速度传感器\",\n                    \"MPU6050\",\n                    \"运动检测\"\n                ],\n                difficulties: [\n                    \"理解三轴加速度的含义\"\n                ],\n                content: `\n# 第14课 运动传感器\n\n## 一、加速度传感器\n\n可以测量物体在三个方向（X、Y、Z）上的加速度。\n\n常用型号：MPU6050\n\n## 二、运动检测应用\n\n### 1. 计步器\n检测行走时的加速度变化，通过算法计算步数。\n\n### 2. 手机横竖屏\n检测手机方向，自动切换屏幕方向。\n\n### 3. 体感游戏\n检测手柄运动，实现游戏控制。\n\n## 三、数据输出\n\n三轴加速度值：\n- X轴加速度\n- Y轴加速度\n- Z轴加速度\n        `,\n                quizIds: [\n                    \"Q1401\"\n                ],\n                simulatorId: \"sim-sensor\"\n            },\n            {\n                id: \"L15\",\n                unitId: \"U3\",\n                number: 15,\n                name: \"数据采集方法\",\n                duration: 45,\n                objectives: [\n                    \"掌握数据采集的基本方法\",\n                    \"了解采样频率的意义\",\n                    \"学会数据存储\"\n                ],\n                keyPoints: [\n                    \"数据采集\",\n                    \"采样频率\",\n                    \"数据存储\"\n                ],\n                difficulties: [\n                    \"理解采样频率的选择\"\n                ],\n                content: `\n# 第15课 数据采集方法\n\n## 一、数据采集流程\n\n\\`\\`\\`\n传感器 → 信号调理 → AD转换 → 数据处理 → 存储/传输\n\\`\\`\\`\n\n## 二、采样频率\n\n采样频率决定数据采集的时间间隔。\n\n**奈奎斯特采样定理**：\n采样频率应大于信号最高频率的2倍。\n\n常用采样频率：\n- 温度：1次/秒\n- 声音：44100次/秒（CD音质）\n- 视频：25-30帧/秒\n\n## 三、数据存储\n\n### 1. 本地存储\n- SD卡\n- 数据库\n\n### 2. 云端存储\n- IoT平台\n- 云数据库\n        `,\n                quizIds: [\n                    \"Q1501\",\n                    \"Q1502\"\n                ],\n                simulatorId: \"sim-sensor\"\n            },\n            {\n                id: \"L16\",\n                unitId: \"U3\",\n                number: 16,\n                name: \"数据处理基础\",\n                duration: 45,\n                objectives: [\n                    \"了解数据处理的目的\",\n                    \"掌握基本数据处理方法\",\n                    \"学会数据可视化\"\n                ],\n                keyPoints: [\n                    \"数据清洗\",\n                    \"数据统计\",\n                    \"数据可视化\"\n                ],\n                difficulties: [\n                    \"理解数据处理的逻辑\"\n                ],\n                content: `\n# 第16课 数据处理基础\n\n## 一、数据清洗\n\n去除异常值、错误数据。\n\n方法：\n- 去除明显错误数据\n- 填补缺失数据\n- 平滑噪声数据\n\n## 二、数据统计\n\n### 1. 描述统计\n- 平均值\n- 最大值、最小值\n- 标准差\n\n### 2. 数据趋势\n- 上升/下降趋势\n- 周期性变化\n\n## 三、数据可视化\n\n用图表直观展示数据。\n\n- 折线图：展示数据变化趋势\n- 柱状图：对比不同类别数据\n- 饼图：展示比例关系\n        `,\n                quizIds: [\n                    \"Q1601\"\n                ],\n                simulatorId: \"sim-visualization\"\n            }\n        ]\n    },\n    {\n        id: \"U4\",\n        number: 4,\n        name: \"物联网通信\",\n        description: \"学习蓝牙、Wi-Fi、MQTT等物联网通信技术和协议\",\n        lessons: [\n            {\n                id: \"L17\",\n                unitId: \"U4\",\n                number: 17,\n                name: \"蓝牙通信\",\n                duration: 45,\n                objectives: [\n                    \"了解蓝牙技术原理\",\n                    \"理解蓝牙通信过程\",\n                    \"掌握蓝牙配对方法\"\n                ],\n                keyPoints: [\n                    \"蓝牙原理\",\n                    \"配对连接\",\n                    \"数据传输\"\n                ],\n                difficulties: [\n                    \"理解蓝牙的配对过程\"\n                ],\n                content: `\n# 第17课 蓝牙通信\n\n## 一、蓝牙技术简介\n\n蓝牙是一种短距离无线通信技术。\n\n**特点**：\n- 传输距离：10-100米\n- 传输速度：1-3Mbps\n- 低功耗\n- 点对点通信\n\n## 二、蓝牙版本\n\n- 蓝牙4.0：低功耗蓝牙（BLE）\n- 蓝牙5.0：传输距离更长、速度更快\n\n## 三、配对连接过程\n\n\\`\\`\\`\n设备扫描 → 发现设备 → 发起配对 → 确认配对 → 建立连接 → 数据传输\n\\`\\`\\`\n\n## 四、应用场景\n\n- 无线耳机\n- 智能手环\n- 文件传输\n- 智能家居控制\n        `,\n                quizIds: [\n                    \"Q1701\",\n                    \"Q1702\"\n                ],\n                simulatorId: \"sim-bluetooth\"\n            },\n            {\n                id: \"L18\",\n                unitId: \"U4\",\n                number: 18,\n                name: \"Wi-Fi通信\",\n                duration: 45,\n                objectives: [\n                    \"了解Wi-Fi通信原理\",\n                    \"理解Wi-Fi网络组成\",\n                    \"学会Wi-Fi配置方法\"\n                ],\n                keyPoints: [\n                    \"Wi-Fi原理\",\n                    \"网络配置\",\n                    \"无线接入\"\n                ],\n                difficulties: [\n                    \"理解Wi-Fi的工作模式\"\n                ],\n                content: `\n# 第18课 Wi-Fi通信\n\n## 一、Wi-Fi技术简介\n\nWi-Fi是基于IEEE 802.11标准的无线局域网技术。\n\n**特点**：\n- 传输距离：几十到几百米\n- 传输速度：几百Mbps到几Gbps\n- 可连接互联网\n- 支持多设备接入\n\n## 二、Wi-Fi网络组成\n\n\\`\\`\\`\n    设备A    设备B    设备C\n      │        │        │\n      └────────┼────────┘\n               ↓\n         无线路由器\n               ↓\n           互联网\n\\`\\`\\`\n\n## 三、Wi-Fi配置\n\n1. 扫描可用的Wi-Fi网络\n2. 选择网络并输入密码\n3. 获取IP地址\n4. 开始通信\n        `,\n                quizIds: [\n                    \"Q1801\"\n                ]\n            },\n            {\n                id: \"L19\",\n                unitId: \"U4\",\n                number: 19,\n                name: \"MQTT协议\",\n                duration: 45,\n                objectives: [\n                    \"理解MQTT协议原理\",\n                    \"掌握发布/订阅模式\",\n                    \"学会MQTT通信方法\"\n                ],\n                keyPoints: [\n                    \"MQTT原理\",\n                    \"发布/订阅\",\n                    \"Topic\"\n                ],\n                difficulties: [\n                    \"理解发布/订阅模式\"\n                ],\n                content: `\n# 第19课 MQTT协议\n\n## 一、MQTT简介\n\nMQTT（Message Queuing Telemetry Transport）是一种轻量级的消息传输协议，专为物联网设计。\n\n**特点**：\n- 轻量级：协议简单，占用资源少\n- 可靠：支持QoS服务质量等级\n- 双向通信：发布/订阅模式\n\n## 二、发布/订阅模式\n\n\\`\\`\\`\n发布者 ──发布消息──→ Broker ──推送消息──→ 订阅者\n                          ↑\n                     Topic主题\n\\`\\`\\`\n\n- **发布者**：发送消息的设备\n- **订阅者**：接收消息的设备\n- **Broker**：消息代理服务器\n- **Topic**：消息主题（类似频道）\n\n## 三、QoS服务质量等级\n\n- QoS 0：最多一次（可能丢失）\n- QoS 1：至少一次（可能重复）\n- QoS 2：恰好一次（不丢不重）\n        `,\n                quizIds: [\n                    \"Q1901\",\n                    \"Q1902\"\n                ],\n                simulatorId: \"sim-mqtt\"\n            },\n            {\n                id: \"L20\",\n                unitId: \"U4\",\n                number: 20,\n                name: \"数据传输\",\n                duration: 45,\n                objectives: [\n                    \"了解数据传输方式\",\n                    \"理解数据包结构\",\n                    \"掌握数据编码方法\"\n                ],\n                keyPoints: [\n                    \"传输方式\",\n                    \"数据格式\",\n                    \"数据编码\"\n                ],\n                difficulties: [\n                    \"理解数据包的结构\"\n                ],\n                content: `\n# 第20课 数据传输\n\n## 一、数据传输方式\n\n### 1. 单工\n只能单向传输（如广播）\n\n### 2. 半双工\n可双向传输，但不能同时（如对讲机）\n\n### 3. 全双工\n可同时双向传输（如电话）\n\n## 二、数据包结构\n\n\\`\\`\\`\n┌────────────────────────────────┐\n│ 头部 │ 数据 │ 校验 │ 尾部    │\n└────────────────────────────────┘\n\\`\\`\\`\n\n- 头部：包含源地址、目标地址等\n- 数据：实际传输的内容\n- 校验：用于错误检测\n- 尾部：数据包结束标志\n\n## 三、数据编码\n\n- JSON格式\n- XML格式\n- 二进制格式\n        `,\n                quizIds: [\n                    \"Q2001\"\n                ]\n            },\n            {\n                id: \"L21\",\n                unitId: \"U4\",\n                number: 21,\n                name: \"网关设备\",\n                duration: 45,\n                objectives: [\n                    \"理解网关的作用\",\n                    \"了解网关的类型\",\n                    \"认识网关在物联网中的地位\"\n                ],\n                keyPoints: [\n                    \"网关定义\",\n                    \"网关功能\",\n                    \"网关类型\"\n                ],\n                difficulties: [\n                    \"理解网关的协议转换功能\"\n                ],\n                content: `\n# 第21课 网关设备\n\n## 一、什么是网关\n\n网关是连接不同网络的设备，负责协议转换和数据转发。\n\n## 二、网关功能\n\n\\`\\`\\`\n传感器网络 ──→ 网关 ──→ 互联网\n(ZigBee)   协议转换    (TCP/IP)\n\\`\\`\\`\n\n- **协议转换**：将传感器协议转换为互联网协议\n- **数据转发**：将数据传输到云端\n- **设备管理**：管理连接的传感器设备\n\n## 三、网关类型\n\n- 家庭网关：智能家居网关\n- 工业网关：工厂数据采集网关\n- 边缘网关：支持边缘计算的网关\n        `,\n                quizIds: [\n                    \"Q2101\"\n                ]\n            },\n            {\n                id: \"L22\",\n                unitId: \"U4\",\n                number: 22,\n                name: \"边缘计算初步\",\n                duration: 45,\n                objectives: [\n                    \"理解边缘计算的概念\",\n                    \"了解边缘计算的优势\",\n                    \"认识边缘计算的应用\"\n                ],\n                keyPoints: [\n                    \"边缘计算定义\",\n                    \"边缘vs云端\",\n                    \"应用场景\"\n                ],\n                difficulties: [\n                    \"理解边缘计算与云计算的区别\"\n                ],\n                content: `\n# 第22课 边缘计算初步\n\n## 一、什么是边缘计算\n\n将计算能力部署在网络边缘（靠近数据源），实现本地数据处理。\n\n\\`\\`\\`\n传统模式：\n设备 ──→ 云端 ──→ 处理 ──→ 返回结果\n\n边缘模式：\n设备 ──→ 边缘节点 ──→ 本地处理 ──→ 结果\n\\`\\`\\`\n\n## 二、边缘计算优势\n\n- **低延迟**：数据处理在本地，响应快\n- **省带宽**：减少数据上传量\n- **高可靠**：断网也能工作\n- **隐私保护**：敏感数据不出本地\n\n## 三、应用场景\n\n- 智能摄像头的人脸识别\n- 自动驾驶汽车的实时决策\n- 工业设备的实时监控\n        `,\n                quizIds: [\n                    \"Q2201\"\n                ]\n            }\n        ]\n    },\n    {\n        id: \"U5\",\n        number: 5,\n        name: \"物联网应用\",\n        description: \"学习智能家居、智慧交通、智慧农业等物联网应用案例\",\n        lessons: [\n            {\n                id: \"L23\",\n                unitId: \"U5\",\n                number: 23,\n                name: \"智能家居\",\n                duration: 45,\n                objectives: [\n                    \"理解智能家居的架构\",\n                    \"了解智能设备联动\",\n                    \"学会设计智能场景\"\n                ],\n                keyPoints: [\n                    \"智能家居架构\",\n                    \"设备联动\",\n                    \"场景设计\"\n                ],\n                difficulties: [\n                    \"理解设备联动规则的设计\"\n                ],\n                content: `\n# 第23课 智能家居\n\n## 一、智能家居架构\n\n\\`\\`\\`\n用户终端（手机APP）\n         ↓\n     云服务器\n         ↓\n    智能网关\n         ↓\n各种智能设备（灯、锁、传感器等）\n\\`\\`\\`\n\n## 二、设备联动\n\n### 示例：回家场景\n1. 门锁检测到开锁\n2. 灯光自动打开\n3. 空调自动开启\n4. 播放欢迎语音\n\n## 三、场景设计\n\n- **离家模式**：关闭所有灯、电器，开启安防\n- **睡眠模式**：关闭卧室以外的灯，调节空调温度\n- **起床模式**：打开窗帘，播放音乐\n        `,\n                quizIds: [\n                    \"Q2301\",\n                    \"Q2302\"\n                ],\n                simulatorId: \"sim-home\"\n            },\n            {\n                id: \"L24\",\n                unitId: \"U5\",\n                number: 24,\n                name: \"智慧农业\",\n                duration: 45,\n                objectives: [\n                    \"了解智慧农业的应用\",\n                    \"理解农业物联网架构\",\n                    \"认识精准农业的意义\"\n                ],\n                keyPoints: [\n                    \"农业物联网\",\n                    \"环境监测\",\n                    \"智能灌溉\"\n                ],\n                difficulties: [\n                    \"理解智慧农业的技术实现\"\n                ],\n                content: `\n# 第24课 智慧农业\n\n## 一、农业物联网应用\n\n### 1. 环境监测\n- 土壤温湿度监测\n- 空气温湿度监测\n- 光照强度监测\n- 二氧化碳浓度监测\n\n### 2. 智能灌溉\n根据土壤湿度自动控制灌溉。\n\n\\`\\`\\`\n土壤湿度传感器 → 控制器 → 电磁阀 → 浇水\n\\`\\`\\`\n\n### 3. 病虫害预警\n通过图像识别检测病虫害。\n\n## 二、精准农业\n\n根据数据精准控制农业生产：\n- 精准施肥\n- 精准灌溉\n- 精准播种\n        `,\n                quizIds: [\n                    \"Q2401\"\n                ]\n            },\n            {\n                id: \"L25\",\n                unitId: \"U5\",\n                number: 25,\n                name: \"智慧交通\",\n                duration: 45,\n                objectives: [\n                    \"了解智慧交通的应用\",\n                    \"理解交通物联网架构\",\n                    \"认识智能交通的意义\"\n                ],\n                keyPoints: [\n                    \"智慧交通\",\n                    \"ETC\",\n                    \"智能停车\"\n                ],\n                difficulties: [\n                    \"理解交通物联网的技术\"\n                ],\n                content: `\n# 第25课 智慧交通\n\n## 一、ETC不停车收费\n\n\\`\\`\\`\n车辆 → OBU(车载单元) → RSU(路侧单元) → 收费系统\n\\`\\`\\`\n\n## 二、智能停车\n\n- 车位检测传感器\n- 车牌识别\n- 空位引导\n- 自动缴费\n\n## 三、智慧交通信号灯\n\n根据车流量自动调整信号灯时长：\n- 检测车流量\n- 计算最优配时\n- 动态调整\n        `,\n                quizIds: [\n                    \"Q2501\"\n                ]\n            },\n            {\n                id: \"L26\",\n                unitId: \"U5\",\n                number: 26,\n                name: \"远程监控\",\n                duration: 45,\n                objectives: [\n                    \"了解远程监控的应用\",\n                    \"理解监控系统架构\",\n                    \"学会使用监控设备\"\n                ],\n                keyPoints: [\n                    \"视频监控\",\n                    \"远程访问\",\n                    \"数据存储\"\n                ],\n                difficulties: [\n                    \"理解监控系统的组成\"\n                ],\n                content: `\n# 第26课 远程监控\n\n## 一、监控系统组成\n\n\\`\\`\\`\n摄像头 → 网络传输 → 云服务器 → 用户查看\n  ↓                     ↓\n本地存储             云存储\n\\`\\`\\`\n\n## 二、智能监控功能\n\n- 人脸识别\n- 移动侦测\n- 声音侦测\n- 异常报警\n\n## 三、应用场景\n\n- 家庭安防\n- 商店监控\n- 学校监控\n- 公共区域监控\n        `,\n                quizIds: [\n                    \"Q2601\"\n                ]\n            },\n            {\n                id: \"L27\",\n                unitId: \"U5\",\n                number: 27,\n                name: \"系统集成\",\n                duration: 45,\n                objectives: [\n                    \"理解系统集成的概念\",\n                    \"了解集成的方法\",\n                    \"学会设计物联网系统\"\n                ],\n                keyPoints: [\n                    \"系统集成\",\n                    \"平台对接\",\n                    \"系统设计\"\n                ],\n                difficulties: [\n                    \"理解多个系统如何集成\"\n                ],\n                content: `\n# 第27课 系统集成\n\n## 一、什么是系统集成\n\n将多个子系统整合为一个协调工作的整体系统。\n\n## 二、集成方法\n\n### 1. 数据集成\n统一数据格式，实现数据共享。\n\n### 2. 接口集成\n通过API接口实现系统间通信。\n\n### 3. 平台集成\n使用统一的物联网平台管理所有设备。\n\n## 三、系统设计步骤\n\n1. 需求分析\n2. 架构设计\n3. 设备选型\n4. 平台搭建\n5. 系统调试\n6. 运行维护\n        `,\n                quizIds: [\n                    \"Q2701\"\n                ],\n                simulatorId: \"sim-home\"\n            }\n        ]\n    },\n    {\n        id: \"U6\",\n        number: 6,\n        name: \"物联网安全\",\n        description: \"学习物联网安全风险、数据隐私保护和安全防护策略\",\n        lessons: [\n            {\n                id: \"L28\",\n                unitId: \"U6\",\n                number: 28,\n                name: \"物联网安全风险\",\n                duration: 45,\n                objectives: [\n                    \"了解物联网的安全风险\",\n                    \"识别常见的安全威胁\",\n                    \"培养安全意识\"\n                ],\n                keyPoints: [\n                    \"安全风险\",\n                    \"常见威胁\",\n                    \"安全意识\"\n                ],\n                difficulties: [\n                    \"理解安全风险的产生原因\"\n                ],\n                content: `\n# 第28课 物联网安全风险\n\n## 一、常见安全风险\n\n### 1. 设备安全\n- 弱密码被破解\n- 设备固件漏洞\n- 设备被劫持\n\n### 2. 网络安全\n- 数据传输被窃听\n- 通信协议漏洞\n- 中间人攻击\n\n### 3. 数据安全\n- 数据泄露\n- 数据篡改\n- 隐私侵犯\n\n## 二、典型攻击案例\n\n- 摄像头被黑客入侵\n- 智能音箱窃听\n- 物联网僵尸网络攻击\n\n## 三、安全意识\n\n- 使用强密码\n- 及时更新固件\n- 谨慎授权\n        `,\n                quizIds: [\n                    \"Q2801\",\n                    \"Q2802\"\n                ]\n            },\n            {\n                id: \"L29\",\n                unitId: \"U6\",\n                number: 29,\n                name: \"数据隐私与保护\",\n                duration: 45,\n                objectives: [\n                    \"理解数据隐私的重要性\",\n                    \"了解隐私保护方法\",\n                    \"学会保护个人隐私\"\n                ],\n                keyPoints: [\n                    \"数据隐私\",\n                    \"隐私保护\",\n                    \"法律法规\"\n                ],\n                difficulties: [\n                    \"理解隐私保护的技术手段\"\n                ],\n                content: `\n# 第29课 数据隐私与保护\n\n## 一、个人隐私数据\n\n- 身份信息\n- 位置信息\n- 行为记录\n- 生物特征（人脸、指纹）\n\n## 二、隐私保护方法\n\n### 1. 数据脱敏\n隐藏或加密敏感信息。\n\n### 2. 权限控制\n限制数据访问权限。\n\n### 3. 最小化收集\n只收集必要的数据。\n\n### 4. 用户授权\n让用户选择是否授权数据收集。\n\n## 三、相关法律法规\n\n- 《个人信息保护法》\n- 《网络安全法》\n- 《数据安全法》\n        `,\n                quizIds: [\n                    \"Q2901\"\n                ]\n            },\n            {\n                id: \"L30\",\n                unitId: \"U6\",\n                number: 30,\n                name: \"安全策略与防范\",\n                duration: 45,\n                objectives: [\n                    \"掌握安全防护策略\",\n                    \"学会识别安全风险\",\n                    \"培养良好的安全习惯\"\n                ],\n                keyPoints: [\n                    \"安全策略\",\n                    \"身份认证\",\n                    \"安全防护\"\n                ],\n                difficulties: [\n                    \"理解多层防护的意义\"\n                ],\n                content: `\n# 第30课 安全策略与防范\n\n## 一、身份认证\n\n### 1. 强密码\n- 长度≥8位\n- 包含大小写字母、数字、特殊符号\n- 定期更换\n\n### 2. 双重认证\n密码 + 验证码/指纹/人脸\n\n### 3. 多因素认证\n结合多种认证方式。\n\n## 二、安全防护策略\n\n\\`\\`\\`\n设备安全 ──→ 网络安全 ──→ 数据安全 ──→ 应用安全\n\\`\\`\\`\n\n### 1. 设备安全\n- 修改默认密码\n- 更新固件\n- 关闭不必要的服务\n\n### 2. 网络安全\n- 使用加密通信\n- 隔离IoT网络\n\n### 3. 数据安全\n- 数据加密存储\n- 定期备份\n\n### 4. 应用安全\n- 安全编程\n- 权限最小化\n        `,\n                quizIds: [\n                    \"Q3001\",\n                    \"Q3002\"\n                ]\n            }\n        ]\n    }\n];\n/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = (curriculum);\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/curriculum/index.ts\n");

